mapper.delete:
DELETE FROM t_account
WHERE user_id = #{userId}
  AND currency = #{currency}

mapper.select:
SELECT COUNT(1)
FROM t_account
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM t_deposit
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM t_deposit
WHERE wallet_tx_id = #{walletTxId}

SELECT status
FROM t_deposit
WHERE wallet_tx_id = #{walletTxId}

SELECT COUNT(1)
FROM t_ledger
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM t_ledger
WHERE user_id = #{userId}
  AND biz_type = #{bizTypeCode}

SELECT CAST(balance AS CHAR)
FROM t_account
WHERE user_id = #{userId}

SELECT CAST(frozen AS CHAR)
FROM t_account
WHERE user_id = #{userId}

SELECT CAST(margin_used AS CHAR)
FROM t_account
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM t_order
WHERE user_id = #{userId}

SELECT status
FROM t_position
WHERE id = #{positionId}

SELECT CAST(close_price AS CHAR)
FROM t_position
WHERE id = #{positionId}

SELECT CAST(take_profit_price AS CHAR)
FROM t_position
WHERE id = #{positionId}

SELECT CAST(stop_loss_price AS CHAR)
FROM t_position
WHERE id = #{positionId}

SELECT CAST(liquidation_price AS CHAR)
FROM t_position
WHERE id = #{positionId}

SELECT close_reason
FROM t_position
WHERE id = #{positionId}

SELECT CAST(realized_pnl AS CHAR)
FROM t_position
WHERE id = #{positionId}

SELECT CAST(closed_at AS CHAR)
FROM t_position
WHERE id = #{positionId}

SELECT COUNT(1)
FROM t_trade
WHERE user_id = #{userId}

SELECT COUNT(1)
FROM t_trade
WHERE position_id = #{positionId}

SELECT COUNT(1)
FROM t_trade
WHERE position_id = #{positionId}
  AND trade_type = #{tradeTypeCode}

SELECT CAST(price AS CHAR)
FROM t_trade
WHERE position_id = #{positionId}
  AND trade_type = #{tradeTypeCode}
ORDER BY traded_at DESC, id DESC
LIMIT 1

SELECT CAST(realized_pnl AS CHAR)
FROM t_trade
WHERE position_id = #{positionId}
  AND trade_type = #{tradeTypeCode}
ORDER BY traded_at DESC, id DESC
LIMIT 1

SELECT CAST(fee AS CHAR)
FROM t_trade
WHERE position_id = #{positionId}
  AND trade_type = #{tradeTypeCode}
ORDER BY traded_at DESC, id DESC
LIMIT 1

SELECT COUNT(1)
FROM t_outbox
WHERE event_type = #{eventType}

SELECT COUNT(1)
FROM t_inbox
WHERE event_id = #{eventId}

SELECT COUNT(1)
FROM t_inbox
WHERE event_type = #{eventType}

SELECT COUNT(1)
FROM t_risk_exposure
WHERE symbol = #{symbol}

SELECT CAST(net_exposure AS CHAR)
FROM t_risk_exposure
WHERE symbol = #{symbol}

SELECT CAST(net_exposure_usd AS CHAR)
FROM t_risk_exposure
WHERE symbol = #{symbol}

SELECT CAST(total_long_qty AS CHAR)
FROM t_risk_exposure
WHERE symbol = #{symbol}

SELECT CAST(total_short_qty AS CHAR)
FROM t_risk_exposure
WHERE symbol = #{symbol}

SELECT CAST(amount AS CHAR)
FROM t_ledger
WHERE user_id = #{userId}
  AND biz_type = #{bizTypeCode}
ORDER BY created_at DESC, id DESC
LIMIT 1

SELECT CAST(balance_after AS CHAR)
FROM t_ledger
WHERE user_id = #{userId}
  AND biz_type = #{bizTypeCode}
ORDER BY created_at DESC, id DESC
LIMIT 1

SELECT CAST(margin_used_after AS CHAR)
FROM t_ledger
WHERE user_id = #{userId}
  AND biz_type = #{bizTypeCode}
ORDER BY created_at DESC, id DESC
LIMIT 1

SELECT COUNT(1)
FROM t_liquidation_log
WHERE position_id = #{positionId}

SELECT COUNT(1)
FROM t_hedge_log
WHERE symbol = #{symbol}
